package org.eclipse.rdf4j.query.algebra.evaluation.sketch.omni;

import static java.lang.foreign.ValueLayout.JAVA_BYTE;
import static java.lang.foreign.ValueLayout.JAVA_INT_UNALIGNED;
import static java.lang.foreign.ValueLayout.JAVA_LONG_UNALIGNED;
import static java.lang.foreign.ValueLayout.JAVA_SHORT_UNALIGNED;

import java.lang.foreign.MemorySegment;
import java.util.Objects;

import org.apache.datasketches.common.SketchesArgumentException;

/** Preamble layout and validation for compact OmniSketch images. */
final class PreambleUtil {
	static final int PREAMBLE_LONGS = 5;
	static final int PREAMBLE_BYTES = PREAMBLE_LONGS << 3;
	static final int SER_VER = 1;

	static final int PREAMBLE_LONGS_BYTE = 0;
	static final int SER_VER_BYTE = 1;
	static final int FAMILY_BYTE = 2;
	static final int LG_WIDTH_BYTE = 3;
	static final int NUM_ROWS_BYTE = 4;
	static final int FLAGS_BYTE = 5;
	static final int SEED_HASH_SHORT = 6;
	static final int NOMINAL_ENTRIES_INT = 8;
	static final int RETAINED_ENTRIES_INT = 12;
	static final int TOTAL_UPDATES_LONG = 16;
	static final int SEED_LONG = 24;
	static final int SERIALIZATION_BYTES_INT = 32;
	static final int RESERVED_INT = 36;

	static final int READ_ONLY_FLAG_MASK = 2;
	static final int EMPTY_FLAG_MASK = 4;
	static final int COMPACT_FLAG_MASK = 8;

	private PreambleUtil() {
	}

	static void insertPreamble(final MemorySegment seg, final OmniSketch sketch, final int retainedEntries,
			final int serializationBytes, final boolean readOnly) {
		Objects.requireNonNull(seg, "Destination MemorySegment must not be null");
		if (seg.byteSize() < serializationBytes) {
			throw new SketchesArgumentException("Destination MemorySegment is too small: " + seg.byteSize()
					+ " < " + serializationBytes);
		}
		seg.set(JAVA_BYTE, PREAMBLE_LONGS_BYTE, (byte) PREAMBLE_LONGS);
		seg.set(JAVA_BYTE, SER_VER_BYTE, (byte) SER_VER);
		seg.set(JAVA_BYTE, FAMILY_BYTE, (byte) OmniSketchFamily.OMNI.getID());
		seg.set(JAVA_BYTE, LG_WIDTH_BYTE, (byte) sketch.getLgWidth());
		seg.set(JAVA_BYTE, NUM_ROWS_BYTE, (byte) sketch.getNumRows());
		int flags = COMPACT_FLAG_MASK;
		if (readOnly) {
			flags |= READ_ONLY_FLAG_MASK;
		}
		if (sketch.isEmpty()) {
			flags |= EMPTY_FLAG_MASK;
		}
		seg.set(JAVA_BYTE, FLAGS_BYTE, (byte) flags);
		seg.set(JAVA_SHORT_UNALIGNED, SEED_HASH_SHORT, OmniSketchHash.seedHash(sketch.getSeed()));
		seg.set(JAVA_INT_UNALIGNED, NOMINAL_ENTRIES_INT, sketch.getNominalEntries());
		seg.set(JAVA_INT_UNALIGNED, RETAINED_ENTRIES_INT, retainedEntries);
		seg.set(JAVA_LONG_UNALIGNED, TOTAL_UPDATES_LONG, sketch.getTotalUpdates());
		seg.set(JAVA_LONG_UNALIGNED, SEED_LONG, sketch.getSeed());
		seg.set(JAVA_INT_UNALIGNED, SERIALIZATION_BYTES_INT, serializationBytes);
		seg.set(JAVA_INT_UNALIGNED, RESERVED_INT, 0);
	}

	static void checkPreamble(final MemorySegment seg) {
		Objects.requireNonNull(seg, "Source MemorySegment must not be null");
		if (seg.byteSize() < PREAMBLE_BYTES) {
			throw new SketchesArgumentException("Input is too small to be an OmniSketch image: " + seg.byteSize());
		}
		final int preLongs = extractPreLongs(seg);
		if (preLongs != PREAMBLE_LONGS) {
			throw new SketchesArgumentException("Invalid OmniSketch preLongs: " + preLongs);
		}
		final int serVer = extractSerVer(seg);
		if (serVer != SER_VER) {
			throw new SketchesArgumentException("Unsupported OmniSketch serialization version: " + serVer);
		}
		final int familyId = extractFamilyId(seg);
		if (familyId != OmniSketchFamily.OMNI.getID()) {
			throw new SketchesArgumentException("MemorySegment is not an OmniSketch image. Family id: " + familyId);
		}
		final int flags = extractFlags(seg);
		if ((flags & COMPACT_FLAG_MASK) == 0) {
			throw new SketchesArgumentException("OmniSketch image must be compact");
		}
		final int lgWidth = extractLgWidth(seg);
		final int numRows = extractNumRows(seg);
		final int nominalEntries = extractNominalEntries(seg);
		if (lgWidth < OmniSketchBuilder.MIN_LG_WIDTH || lgWidth > OmniSketchBuilder.MAX_LG_WIDTH) {
			throw new SketchesArgumentException("Invalid OmniSketch lgWidth: " + lgWidth);
		}
		if (numRows < 1 || numRows > OmniSketchBuilder.MAX_NUM_ROWS) {
			throw new SketchesArgumentException("Invalid OmniSketch numRows: " + numRows);
		}
		if (nominalEntries < 1) {
			throw new SketchesArgumentException("Invalid OmniSketch nominalEntries: " + nominalEntries);
		}
		final long seed = extractSeed(seg);
		if (extractSeedHash(seg) != OmniSketchHash.seedHash(seed)) {
			throw new SketchesArgumentException("Seed hash mismatch while reading OmniSketch image");
		}
		final int serializationBytes = extractSerializationBytes(seg);
		if (serializationBytes < PREAMBLE_BYTES || serializationBytes > seg.byteSize()) {
			throw new SketchesArgumentException("Invalid OmniSketch serialization byte count: " + serializationBytes);
		}
	}

	static int extractPreLongs(final MemorySegment seg) {
		return seg.get(JAVA_BYTE, PREAMBLE_LONGS_BYTE) & 0x3F;
	}

	static int extractSerVer(final MemorySegment seg) {
		return seg.get(JAVA_BYTE, SER_VER_BYTE) & 0xFF;
	}

	static int extractFamilyId(final MemorySegment seg) {
		return seg.get(JAVA_BYTE, FAMILY_BYTE) & 0xFF;
	}

	static int extractLgWidth(final MemorySegment seg) {
		return seg.get(JAVA_BYTE, LG_WIDTH_BYTE) & 0xFF;
	}

	static int extractNumRows(final MemorySegment seg) {
		return seg.get(JAVA_BYTE, NUM_ROWS_BYTE) & 0xFF;
	}

	static int extractFlags(final MemorySegment seg) {
		return seg.get(JAVA_BYTE, FLAGS_BYTE) & 0xFF;
	}

	static short extractSeedHash(final MemorySegment seg) {
		return seg.get(JAVA_SHORT_UNALIGNED, SEED_HASH_SHORT);
	}

	static int extractNominalEntries(final MemorySegment seg) {
		return seg.get(JAVA_INT_UNALIGNED, NOMINAL_ENTRIES_INT);
	}

	static int extractRetainedEntries(final MemorySegment seg) {
		return seg.get(JAVA_INT_UNALIGNED, RETAINED_ENTRIES_INT);
	}

	static long extractTotalUpdates(final MemorySegment seg) {
		return seg.get(JAVA_LONG_UNALIGNED, TOTAL_UPDATES_LONG);
	}

	static long extractSeed(final MemorySegment seg) {
		return seg.get(JAVA_LONG_UNALIGNED, SEED_LONG);
	}

	static int extractSerializationBytes(final MemorySegment seg) {
		return seg.get(JAVA_INT_UNALIGNED, SERIALIZATION_BYTES_INT);
	}

	static boolean isEmpty(final MemorySegment seg) {
		return (extractFlags(seg) & EMPTY_FLAG_MASK) != 0;
	}

	static String preambleToString(final MemorySegment seg) {
		checkPreamble(seg);
		final String nl = System.lineSeparator();
		final StringBuilder sb = new StringBuilder();
		sb.append(nl);
		sb.append("### OMNISKETCH PREAMBLE SUMMARY:").append(nl);
		sb.append("Byte  0: Preamble Longs       : ").append(extractPreLongs(seg)).append(nl);
		sb.append("Byte  1: Serialization Version: ").append(extractSerVer(seg)).append(nl);
		sb.append("Byte  2: Family               : ")
				.append(extractFamilyId(seg))
				.append(", ")
				.append(OmniSketchFamily.idToFamily(extractFamilyId(seg)))
				.append(nl);
		sb.append("Byte  3: LgWidth              : ").append(extractLgWidth(seg)).append(nl);
		sb.append("Byte  4: NumRows              : ").append(extractNumRows(seg)).append(nl);
		sb.append("Byte  5: Flags                : ").append(extractFlags(seg)).append(nl);
		sb.append("Bytes 6-7: Seed Hash          : ")
				.append(Integer.toHexString(extractSeedHash(seg) & 0xFFFF))
				.append(nl);
		sb.append("Bytes 8-11: Nominal Entries   : ").append(extractNominalEntries(seg)).append(nl);
		sb.append("Bytes 12-15: Retained Entries : ").append(extractRetainedEntries(seg)).append(nl);
		sb.append("Bytes 16-23: Total Updates    : ").append(extractTotalUpdates(seg)).append(nl);
		sb.append("Bytes 24-31: Seed             : ").append(extractSeed(seg)).append(nl);
		sb.append("Bytes 32-35: Serialized Bytes : ").append(extractSerializationBytes(seg)).append(nl);
		sb.append("### END OMNISKETCH PREAMBLE SUMMARY").append(nl);
		return sb.toString();
	}
}
